package github.chains;

import com.github.javaparser.JavaParser;
import com.github.javaparser.ParseResult;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.type.Type;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.StandardCopyOption;
import java.util.List;

public class Main {
    public static void main(String[] args) throws IOException {
        String inputFile = "/workspace/polyglot-maven/polyglot-yaml/src/main/java/org/sonatype/maven/polyglot/yaml/ModelRepresenter.java";
        String backupFile = inputFile + ".backup";

        Path inputPath = Paths.get(inputFile);
        Path backupPath = Paths.get(backupFile);

        Files.copy(inputPath, backupPath, StandardCopyOption.REPLACE_EXISTING);
        System.out.println("Backup created: " + backupFile);

        String sourceCode = Files.readString(inputPath);

        JavaParser javaParser = new JavaParser();
        ParseResult<CompilationUnit> parseResult = javaParser.parse(sourceCode);

        if (!parseResult.isSuccessful() || !parseResult.getResult().isPresent()) {
            System.err.println("Failed to parse file: " + parseResult.getIssues());
            return;
        }

        CompilationUnit cu = parseResult.getResult().get();

        List<MethodDeclaration> methods = cu.findAll(MethodDeclaration.class);
        int modifications = 0;

        for (MethodDeclaration method : methods) {
            if ("getProperties".equals(method.getNameAsString())) {
                List<Type> thrownExceptions = method.getThrownExceptions();
                for (int i = thrownExceptions.size() - 1; i >= 0; i--) {
                    Type exception = thrownExceptions.get(i);
                    if ("IntrospectionException".equals(exception.getTypeAsString()) ||
                        "java.beans.IntrospectionException".equals(exception.getTypeAsString())) {
                        exception.remove();
                        modifications++;
                        System.out.println("Removed IntrospectionException from method: " + method.getSignature());
                    }
                }
            }
        }

        if (modifications > 0) {
            Files.writeString(inputPath, cu.toString());
            System.out.println("Transformation complete! Modified " + modifications + " method(s).");
        } else {
            System.out.println("No modifications needed.");
            Files.copy(backupPath, inputPath, StandardCopyOption.REPLACE_EXISTING);
        }
    }
}

